import React from 'react';

type JobEventSkipInfoProps = {
  setsSkipped?: number | null;
  setsFailed?: number | null;
  documentsTotal?: number | null;
};

export const JobEventSkipInfo: React.FC<JobEventSkipInfoProps> = ({
  setsSkipped,
  setsFailed,
  documentsTotal,
}) => {
  const skip = setsSkipped ?? 0;
  const fail = setsFailed ?? 0;

  if (skip === 0 && fail === 0)
    return <span style={{ color: '#94a3b8' }}>—</span>;

  const parts: string[] = [];
  if (skip > 0) parts.push(`Skip ${skip}${documentsTotal ? `/${documentsTotal}` : ''}`);
  if (fail > 0) parts.push(`Fail ${fail}`);

  return (
    <span style={{ fontSize: 12, color: '#64748b' }} title={parts.join(' · ')}>
      {parts.join(' · ')}
    </span>
  );
};
