/** Shared job/import status labels and colors for admin/jobs pages. */

export const jobStatusColor = (status: string): string => {
  switch (status) {
    case 'Success':
    case 'Completed':
    case 'Done':
      return '#15803d';
    case 'Failed':
    case 'DeadLetter':
      return '#b91c1c';
    case 'Running':
    case 'Processing':
      return '#2563eb';
    case 'Partial':
    case 'RetryPending':
      return '#ca8a04';
    case 'Skipped':
    case 'Skip':
      return '#64748b';
    default:
      return '#64748b';
  }
};

/** External sync run status from BE → UI label. */
export const displayExternalRunStatus = (status: string): string => {
  if (status === 'Success') return 'Done';
  return status;
};

/** Import run status from BE → UI label. */
export const displayImportRunStatus = (status: string): string => {
  if (status === 'Success') return 'Done';
  if (status === 'Skipped') return 'Skip';
  return status;
};

/** Platform event processing status → UI label. */
export const displayEventStatus = (status: string): string => {
  if (status === 'Done') return 'Done';
  return status;
};

/** Run status shown on event rows — aligns with BE effective run status. */
export const displayLinkedRunStatus = (status: string): string => {
  if (status === 'Success') return 'Done';
  if (status === 'Skipped') return 'Skip';
  if (status === 'RetryPending') return 'Chờ retry';
  return status;
};

/** Prefer event outcome when viewing a single event row/detail. */
export const resolveRunStatusFromEvent = (detail: {
  processingStatus: string;
  runStatus?: string | null;
  nextRetryAt?: string | null;
  attemptCount: number;
  maxAttempts: number;
}): string | null => {
  if (detail.processingStatus === 'Failed') {
    if (detail.nextRetryAt && detail.attemptCount < detail.maxAttempts) return 'RetryPending';
    return 'Failed';
  }
  if (detail.processingStatus === 'DeadLetter') return 'Failed';
  if (detail.processingStatus === 'Pending' || detail.processingStatus === 'Processing') return 'Running';
  return detail.runStatus ?? null;
};

export const isJobRunningStatus = (status: string): boolean =>
  status === 'Running' || status === 'Processing';

export const canRetryImportRun = (status: string): boolean =>
  status === 'Failed' || status === 'Partial';
