import React from 'react';
import { Button } from '../../../ui';
import styles from '../JobInternalPage.module.css';

export type JobDetailMetaItem = {
  label: string;
  value: React.ReactNode;
  mono?: boolean;
  fullWidth?: boolean;
};

export const formatJobDate = (iso?: string | null): string | null =>
  iso ? new Date(iso).toLocaleString('vi-VN') : null;

export const JobDetailMonoId: React.FC<{ children: React.ReactNode }> = ({ children }) => (
  <p className={styles.detailMonoId}>{children}</p>
);

export const JobDetailSection: React.FC<{ title: string; children: React.ReactNode }> = ({
  title,
  children,
}) => (
  <section className={styles.detailSection}>
    <h5 className={styles.detailSectionTitle}>{title}</h5>
    {children}
  </section>
);

export const JobDetailCollapsibleSection: React.FC<{
  title: string;
  defaultOpen?: boolean;
  children: React.ReactNode;
}> = ({ title, defaultOpen = false, children }) => (
  <details className={styles.detailSetExpand} open={defaultOpen}>
    <summary>{title}</summary>
    <div className={styles.detailExpandBody}>{children}</div>
  </details>
);

export const JobDetailMetaGrid: React.FC<{ items: JobDetailMetaItem[] }> = ({ items }) => (
  <div className={styles.detailMetaGrid}>
    {items.map((item) => (
      <div
        key={item.label}
        className={item.fullWidth ? styles.detailMetaItemFull : styles.detailMetaItem}
      >
        <div className={styles.detailMetaLabel}>{item.label}</div>
        <div className={item.mono ? styles.detailMetaValueMono : styles.detailMetaValue}>
          {item.value ?? '—'}
        </div>
      </div>
    ))}
  </div>
);

export const JobDetailErrorBlock: React.FC<{
  error: string;
  category?: string | null;
  title?: string;
  copyTestId?: string;
}> = ({ error, category, title = 'Lý do lỗi', copyTestId = 'job-event-copy-fail-reason' }) => {
  const [copied, setCopied] = React.useState(false);

  const handleCopy = async () => {
    const text = category ? `[${category}]\n${error}` : error;
    try {
      await navigator.clipboard.writeText(text);
      setCopied(true);
      window.setTimeout(() => setCopied(false), 2000);
    } catch {
      setCopied(false);
    }
  };

  return (
    <div className={styles.detailErrorBlock}>
      <div className={styles.detailErrorHeader}>
        <div className={styles.detailErrorTitle}>{title}</div>
        <Button type="button" variant="secondary" onClick={handleCopy} data-testid={copyTestId}>
          {copied ? 'Đã copy' : 'Copy'}
        </Button>
      </div>
      {category ? (
        <div className={styles.detailMetaLabel} style={{ marginBottom: 6 }}>
          Failure category: <strong>{category}</strong>
        </div>
      ) : null}
      <pre className={styles.detailErrorPre}>{error}</pre>
    </div>
  );
};
