import React from 'react';
import { Link } from 'react-router-dom';
import { Button } from '../../../ui';
import type { ImportRunDetail, ImportRunSummary, ImportSetResult } from '../../../services/jobs';
import { JobProgressBar } from './JobProgressBar';
import {
  JobDetailMetaGrid,
  JobDetailMonoId,
  JobDetailSection,
  formatJobDate,
  type JobDetailMetaItem,
} from './JobDetailMetaGrid';
import {
  aggregateRunRecordStats,
  aggregateSetRecordStats,
  formatImportRecordStatsLine,
  formatImportSetsSummaryLine,
  showImportRecordStats,
} from '../importRunRecordStats';
import styles from '../JobInternalPage.module.css';
import { displayImportRunStatus, jobStatusColor } from '../jobStatusDisplay';

const summaryMetaItems = (summary: ImportRunSummary): JobDetailMetaItem[] => [
  { label: 'Sets ok', value: `${summary.setsSuccess}/${summary.setsTotal}` },
  { label: 'Partial', value: summary.setsPartial > 0 ? summary.setsPartial : '—' },
  { label: 'Failed sets', value: summary.setsFailed > 0 ? summary.setsFailed : '—' },
  { label: 'Skipped sets', value: summary.setsSkipped > 0 ? summary.setsSkipped : '—' },
  { label: 'Catalog rows', value: summary.catalogRowsTotal?.toLocaleString('vi-VN') ?? '—' },
  { label: 'Catalog upserted', value: summary.catalogRowsUpserted?.toLocaleString('vi-VN') ?? '—' },
  { label: 'Catalog failed', value: summary.catalogRowsFailed?.toLocaleString('vi-VN') ?? '—' },
  { label: 'Voucher headers', value: summary.voucherHeadersTotal?.toLocaleString('vi-VN') ?? '—' },
  { label: 'Voucher upserted', value: summary.voucherHeadersUpserted?.toLocaleString('vi-VN') ?? '—' },
  { label: 'Posted', value: summary.voucherHeadersPosted?.toLocaleString('vi-VN') ?? '—' },
  { label: 'Draft', value: summary.voucherHeadersDraft?.toLocaleString('vi-VN') ?? '—' },
  { label: 'Voucher lines', value: summary.voucherLinesTotal?.toLocaleString('vi-VN') ?? '—' },
  { label: 'Mã CT gán', value: summary.voucherCodesAssigned?.toLocaleString('vi-VN') ?? '—' },
  { label: 'Mã CT mới', value: summary.voucherCodesNewInsert?.toLocaleString('vi-VN') ?? '—' },
  { label: 'Lỗi mẫu', value: summary.errorSampleCount?.toLocaleString('vi-VN') ?? '—' },
];

const SetCatalogBreakdown: React.FC<{ set: ImportSetResult }> = ({ set }) => {
  if (set.catalogs.length === 0) {
    return null;
  }

  return (
    <details className={styles.detailSetExpand}>
      <summary>
        {set.setName} — {set.catalogs.length} catalog
        {set.progress
          ? ` · ${set.progress.documentsDone}/${set.progress.documentsTotal} (${set.progress.progressPercent}%)`
          : ''}
      </summary>
      <table className={styles.detailSubTable}>
        <thead>
          <tr>
            <th>Catalog</th>
            <th>File</th>
            <th>Outcome</th>
            <th align="right">Total</th>
            <th align="right">Upsert</th>
            <th align="right">Fail</th>
            <th align="right">Skip</th>
            <th align="right">Posted</th>
            <th align="right">Draft</th>
          </tr>
        </thead>
        <tbody>
          {set.catalogs.map((c) => (
            <tr key={`${set.setName}-${c.catalog}-${c.fileName}`}>
              <td>{c.catalog}</td>
              <td>{c.fileName}</td>
              <td>{c.outcome}</td>
              <td align="right">{c.rowsTotal.toLocaleString('vi-VN')}</td>
              <td align="right">{c.rowsUpserted.toLocaleString('vi-VN')}</td>
              <td align="right" style={{ color: c.rowsFailed > 0 ? '#b91c1c' : undefined }}>
                {c.rowsFailed.toLocaleString('vi-VN')}
              </td>
              <td align="right">{c.rowsSkipped > 0 ? c.rowsSkipped.toLocaleString('vi-VN') : '—'}</td>
              <td align="right">{c.rowsPosted > 0 ? c.rowsPosted.toLocaleString('vi-VN') : '—'}</td>
              <td align="right">{c.rowsDraft > 0 ? c.rowsDraft.toLocaleString('vi-VN') : '—'}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </details>
  );
};

export type JobImportRunDetailPanelProps = {
  runDetail: ImportRunDetail | null;
  loading?: boolean;
  onCopyErrors?: () => void;
  copiedErrors?: boolean;
  showEventsLink?: boolean;
};

export const JobImportRunDetailPanel: React.FC<JobImportRunDetailPanelProps> = ({
  runDetail,
  loading = false,
  onCopyErrors,
  copiedErrors = false,
  showEventsLink = true,
}) => {
  if (loading && !runDetail) {
    return <p>Đang tải…</p>;
  }
  if (!runDetail) {
    return <p style={{ color: '#64748b' }}>Không tải được chi tiết import run.</p>;
  }

  const overviewItems: JobDetailMetaItem[] = [
    {
      label: 'Trạng thái',
      value: (
        <span style={{ color: jobStatusColor(runDetail.status) }}>
          {displayImportRunStatus(runDetail.status)}
        </span>
      ),
    },
    { label: 'Trigger', value: runDetail.trigger },
    { label: 'Environment', value: runDetail.environmentName },
    { label: 'Source kind', value: runDetail.sourceKind ?? 'CSV' },
    ...(runDetail.companyId ? [{ label: 'Company ID', value: runDetail.companyId, mono: true } satisfies JobDetailMetaItem] : []),
    { label: 'Bắt đầu', value: formatJobDate(runDetail.startedAtUtc) },
    { label: 'Kết thúc', value: formatJobDate(runDetail.finishedAtUtc) ?? '—' },
    ...(runDetail.progressPercent != null
      ? [{ label: 'Tiến độ (run)', value: `${runDetail.progressPercent}%` } satisfies JobDetailMetaItem]
      : []),
    ...(runDetail.documentsDone != null && runDetail.documentsTotal != null
      ? [
          {
            label: 'Documents',
            value: `${runDetail.documentsDone}/${runDetail.documentsTotal}`,
          } satisfies JobDetailMetaItem,
        ]
      : []),
  ];

  return (
    <>
      <JobDetailMonoId>{runDetail.id}</JobDetailMonoId>

      <JobDetailSection title="Tổng quan">
        <JobDetailMetaGrid items={overviewItems} />
      </JobDetailSection>

      {runDetail.setsRequested.length > 0 ? (
        <JobDetailSection title="Sets yêu cầu">
          <div className={styles.detailChipList}>
            {runDetail.setsRequested.map((setName) => (
              <span key={setName} className={styles.detailChip}>
                {setName}
              </span>
            ))}
          </div>
        </JobDetailSection>
      ) : null}

      <JobDetailSection title="Tóm tắt import">
        <p style={{ fontSize: 13, margin: '0 0 8px' }}>{formatImportSetsSummaryLine(runDetail.summary)}</p>
        <JobDetailMetaGrid items={summaryMetaItems(runDetail.summary)} />
      </JobDetailSection>

      {showImportRecordStats(runDetail.status) ? (
        <p
          style={{
            fontSize: 13,
            marginBottom: 12,
            fontWeight: 600,
            color: jobStatusColor(runDetail.status),
          }}
          data-testid="job-import-record-stats"
        >
          {formatImportRecordStatsLine(
            aggregateRunRecordStats(runDetail.summary, runDetail.setResults),
          )}
        </p>
      ) : null}

      {runDetail.progress ? (
        <JobDetailSection title="Tiến độ checkpoint">
          <JobProgressBar
            percent={runDetail.progressPercent ?? runDetail.progress.progressPercent}
            done={runDetail.progress.documentsDone}
            total={runDetail.progress.documentsTotal}
          />
          <ul style={{ margin: '8px 0 0', paddingLeft: 18, fontSize: 13 }}>
            {runDetail.progress.sets.map((s) => (
              <li key={s.setName}>
                {s.setName} ({s.sourceKind}): {s.documentsDone}/{s.documentsTotal} xong
                {s.documentsFailed > 0 ? `, ${s.documentsFailed} lỗi` : ''}
                {s.documentsPending > 0 ? `, ${s.documentsPending} chờ` : ''} ({s.progressPercent}%)
              </li>
            ))}
          </ul>
        </JobDetailSection>
      ) : (
        <p style={{ color: '#64748b', fontSize: 13, marginBottom: 12 }}>Chưa có checkpoint progress.</p>
      )}

      {runDetail.setResults.length > 0 ? (
        <JobDetailSection title="Kết quả theo set">
          <div className={styles.detailTableWrap}>
            <table className={styles.detailTable}>
              <thead>
                <tr>
                  <th>Set</th>
                  <th>Status</th>
                  <th align="right">Pass</th>
                  <th align="right">Fail</th>
                  <th align="right">Draft</th>
                  <th align="right">Lỗi mẫu</th>
                  <th align="right">Mã CT mẫu</th>
                </tr>
              </thead>
              <tbody>
                {runDetail.setResults.map((s) => {
                  const records = aggregateSetRecordStats(s);
                  return (
                    <tr key={s.setName}>
                      <td>{s.setName}</td>
                      <td style={{ color: jobStatusColor(s.status) }}>
                        {s.skipped ? `Skipped${s.skipReason ? ` — ${s.skipReason}` : ''}` : s.status}
                      </td>
                      <td align="right">{records.pass.toLocaleString('vi-VN')}</td>
                      <td align="right" style={{ color: records.fail > 0 ? '#b91c1c' : undefined }}>
                        {records.fail.toLocaleString('vi-VN')}
                      </td>
                      <td align="right" style={{ color: records.draft > 0 ? '#ca8a04' : undefined }}>
                        {records.draft > 0 ? records.draft.toLocaleString('vi-VN') : '—'}
                      </td>
                      <td align="right">{s.errorCount}</td>
                      <td align="right">{s.voucherCodeSampleCount ?? 0}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>

          {runDetail.setResults.some((s) => s.catalogs.length > 0) ? (
            <div style={{ marginTop: 10 }}>
              {runDetail.setResults.map((s) => (
                <SetCatalogBreakdown key={s.setName} set={s} />
              ))}
            </div>
          ) : null}
        </JobDetailSection>
      ) : null}

      {runDetail.voucherCodeSamples.length > 0 ? (
        <JobDetailSection title={`Mã chứng từ gán (${runDetail.voucherCodeSamples.length})`}>
          <div className={styles.detailTableWrap}>
            <table className={styles.detailTable}>
              <thead>
                <tr>
                  <th>Set</th>
                  <th>Catalog</th>
                  <th>Legacy ID</th>
                  <th>Legacy code</th>
                  <th>Mã CT</th>
                  <th>Prefix</th>
                  <th>Ngày CT</th>
                  <th>Mới</th>
                </tr>
              </thead>
              <tbody>
                {runDetail.voucherCodeSamples.map((v, idx) => (
                  <tr key={`${v.setName}-${v.legacyId}-${v.voucherCode}-${idx}`}>
                    <td>{v.setName}</td>
                    <td>{v.catalog}</td>
                    <td className={styles.gridMono}>{v.legacyId}</td>
                    <td>{v.legacyCode ?? '—'}</td>
                    <td className={styles.gridMono}>{v.voucherCode}</td>
                    <td>{v.idCodePrefix}</td>
                    <td>{v.voucherDate}</td>
                    <td>{v.isNewInsert ? 'Có' : '—'}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </JobDetailSection>
      ) : null}

      {runDetail.errorSamples.length > 0 ? (
        <JobDetailSection title={`Mẫu lỗi (${runDetail.errorSamples.length})`}>
          <div className={styles.errorSamplesHeader}>
            <span style={{ fontSize: 12, color: '#64748b' }}>Hiển thị đầy đủ message + gợi ý xử lý</span>
            {onCopyErrors ? (
              <Button
                type="button"
                variant="secondary"
                onClick={onCopyErrors}
                data-testid="job-import-copy-errors"
              >
                {copiedErrors ? 'Đã copy' : 'Copy JSON'}
              </Button>
            ) : null}
          </div>
          <div className={styles.detailTableWrap}>
            <table className={styles.detailTable}>
              <thead>
                <tr>
                  <th>Set</th>
                  <th>Catalog</th>
                  <th>Mã / rowKey</th>
                  <th>Error code</th>
                  <th>Message</th>
                  <th>Gợi ý</th>
                </tr>
              </thead>
              <tbody>
                {runDetail.errorSamples.map((e, idx) => (
                  <tr key={`${e.setName}-${e.rowKey}-${idx}`}>
                    <td>{e.setName}</td>
                    <td>{e.catalog}</td>
                    <td>{e.code ?? e.rowKey}</td>
                    <td>{e.errorCode}</td>
                    <td>{e.message}</td>
                    <td>
                      {e.actionLabelVi ?? e.suggestedAction}
                      {e.deepLinkPath ? (
                        <>
                          <br />
                          <a className={styles.detailActionLink} href={e.deepLinkPath} target="_blank" rel="noreferrer">
                            {e.deepLinkPath}
                          </a>
                        </>
                      ) : null}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </JobDetailSection>
      ) : null}

      {runDetail.status === 'Running' ? (
        <p style={{ fontSize: 12, color: '#64748b', margin: '0 0 12px' }}>
          Run đang chạy — poll tự động 4s.
        </p>
      ) : null}

      {showEventsLink ? (
        <Link to="/admin/jobs/events?direction=Internal" style={{ fontSize: 13 }}>
          Xem events Internal →
        </Link>
      ) : null}
    </>
  );
};
